#include <iostream>
using namespace std;
struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(NULL) {}
};
ListNode* deleteHead(ListNode* head) {
    // implement
    return head->next;
}

// @driver-code-start
int main() {
    int n;
    cin >> n;
    ListNode* head = NULL;
    ListNode* curr = NULL;
    for (int i = 0; i < n; i++) {
        int val;
        cin >> val;
        ListNode* node = new ListNode(val);
        if (head == NULL) {
            head = node;
            curr = head;
        } else {
            curr->next = node;
            curr = curr->next;
        }
    }
    ListNode* newHead = deleteHead(head);
    int count = 0;
    while (newHead) {
        cout << newHead->val << " ";
        newHead = newHead->next;
        count++;
    }
    cout << endl;
    cout << count << endl;
    return 0;
}

